module RefModule(
    input [15:0]D0,
    input [7:0]D1,
    input [2:0]OP,	
    output [15:0]DOUT
    );
	reg [7:0] unused_mux;
	always @*
		case(OP)
			0: unused_mux = 8'h00;	
			1: unused_mux = 8'h01;	
			2: unused_mux = 8'h02;	
			3: unused_mux = D1;		
			4: unused_mux = 8'h00;	
			5: unused_mux = 8'hff;	
			6: unused_mux = 8'hfe;	
			default: unused_mux = 8'hxx;
		endcase
	assign DOUT = D0 + {{8{unused_mux[7]}}, unused_mux};
endmodule
